# Maps the public ``process_priority`` values to a POSIX ``nice`` increment.
# Positive values lower the priority (nicer), negative values raise it.
_UNIX_NICE_VALUES = {
    "low": 10,
    "below_normal": 5,
    "normal": 0,
    "above_normal": -5,
    "high": -10,
}

# The Windows priority class names corresponding to the same values. Looked
# up lazily since these constants only exist on Windows builds of `subprocess`.
_WINDOWS_PRIORITY_CLASS_NAMES = {
    "low": "IDLE_PRIORITY_CLASS",
    "below_normal": "BELOW_NORMAL_PRIORITY_CLASS",
    "normal": "NORMAL_PRIORITY_CLASS",
    "above_normal": "ABOVE_NORMAL_PRIORITY_CLASS",
    "high": "HIGH_PRIORITY_CLASS",
}


def _set_unix_process_priority(nice_value: int) -> None:
    try:
        os.nice(nice_value)
    except OSError:
        # Raising a lower nice value (higher priority) typically requires
        # elevated privileges. Fall back to the default priority instead
        # of failing the edit operation.
        pass


class Editor:
    def __init__(
        self,
        editor: str | None = None,
        env: cabc.Mapping[str, str] | None = None,
        require_save: bool = True,
        extension: str = ".txt",
        process_priority: str | None = None,
    ) -> None:
        self.editor = editor
        self.env = env
        self.require_save = require_save
        self.extension = extension
        self.process_priority = process_priority

    def get_editor(self) -> str:
        if self.editor is not None:
            return self.editor
        for key in "VISUAL", "EDITOR":
            rv = os.environ.get(key)
            if rv:
                return rv
        if WIN:
            return "notepad"
        for editor in "sensible-editor", "vim", "nano":
            if os.system(f"which {editor} >/dev/null 2>&1") == 0:
                return editor
        return "vi"

    def _get_popen_priority_kwargs(self) -> dict[str, t.Any]:
        if self.process_priority not in _UNIX_NICE_VALUES:
            return {}

        if WIN:
            import subprocess

            priority_class = getattr(
                subprocess, _WINDOWS_PRIORITY_CLASS_NAMES[self.process_priority], None
            )
            if priority_class is None:
                return {}
            return {"creationflags": priority_class}

        nice_value = _UNIX_NICE_VALUES[self.process_priority]
        return {"preexec_fn": lambda: _set_unix_process_priority(nice_value)}

    def edit_file(self, filename: str) -> None:
        import subprocess

        editor = self.get_editor()
        environ: dict[str, str] | None = None

        if self.env:
            environ = os.environ.copy()
            environ.update(self.env)

        try:
            c = subprocess.Popen(
                f'{editor} "{filename}"',
                env=environ,
                shell=True,
                **self._get_popen_priority_kwargs(),
            )
            exit_code = c.wait()
            if exit_code != 0:
                raise ClickException(
                    _("{editor}: Editing failed").format(editor=editor)
                )
        except OSError as e:
            raise ClickException(
                _("{editor}: Editing failed: {e}").format(editor=editor, e=e)
            ) from e

